// Ultra-Advanced Validation for WhatsApp Messages
const items = $input.all();

function isEmptyOrInvalid(str) {
  if (!str || typeof str !== 'string') return true;
  const trimmed = str.trim();
  if (trimmed.length === 0) return true;
  const invalidOnlyPattern = /^[\s\u00A0\u1680\u2000-\u200B\u202F\u205F\u3000\uFEFF"'`<>,.!?;:\-_=+(){}\[\]\/\\|~@#$%^&*]*$/;
  if (invalidOnlyPattern.test(trimmed)) return true;
  return false;
}

function isMeaningless(str) {
  if (!str || typeof str !== 'string') return true;
  const trimmed = str.trim();
  if (trimmed.length === 1) {
    const char = trimmed;
    if (/[a-zA-Z0-9]/.test(char)) return false;
    if (['✓', '✔', '✅', '❌', '👍', '👎', '✋', '🙏'].includes(char)) return false;
    if (/[<>!?.,;:'"=+\-_*&^%$#@~`|\\\/(){}\[\]]/.test(char)) return true;
  }
  if (trimmed.length <= 2) {
    if (/^[^a-zA-Z0-9\u{1F300}-\u{1F9FF}]+$/u.test(trimmed)) return true;
  }
  if (/^(.)\1{2,}$/.test(trimmed) && trimmed.length <= 10) {
    if (!/^[a-zA-Z0-9]+$/.test(trimmed)) return false;
    return true;
  }
  return false;
}

function sanitizeMessage(str) {
  if (!str || typeof str !== 'string') return '';
  let sanitized = str.trim();
  sanitized = sanitized.replace(/\s+/g, ' ');
  sanitized = sanitized.replace(/[\u200B-\u200D\uFEFF\u00AD]/g, '');
  sanitized = sanitized.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');
  sanitized = sanitized.replace(/([!?.;,]){4,}/g, '$1$1$1');
  sanitized = sanitized.replace(/^[<>{}()\[\]]+|[<>{}()\[\]]+$/g, '');
  return sanitized.trim();
}

function containsSuspiciousPatterns(str) {
  if (!str || typeof str !== 'string') return false;
  const suspiciousPatterns = [
    /<script[\s\S]*?>[\s\S]*?<\/script>/gi,
    /javascript:/gi,
    /on\w+\s*=/gi,
    /<iframe/gi,
    /eval\s*\(/gi,
    /expression\s*\(/gi,
    /<object/gi,
    /<embed/gi,
    /vbscript:/gi,
    /data:text\/html/gi,
  ];
  return suspiciousPatterns.some(pattern => pattern.test(str));
}

function isSpamPattern(str) {
  if (!str || typeof str !== 'string') return false;
  const capitals = (str.match(/[A-Z]/g) || []).length;
  const letters = (str.match(/[a-zA-Z]/g) || []).length;
  if (letters > 5 && (capitals / letters) > 0.7) return true;
  const words = str.toLowerCase().split(/\s+/);
  const uniqueWords = new Set(words);
  if (words.length > 10 && uniqueWords.size < words.length * 0.3) return true;
  return false;
}

for (const item of items) {
  const message = item.json.messages?.[0];
  let isValid = false;
  let validationError = null;
  let userFriendlyError = null;
  let messageContent = null;
  let messageType = null;

  if (!message) {
    validationError = "Message data is missing in the incoming payload";
    userFriendlyError = "Sorry, we couldn't process your message. Please try again.";
  } else if (message.type === 'text') {
    const rawText = message.text?.body;
    if (!rawText) {
      validationError = "Text message body is null or undefined";
      userFriendlyError = "Please send a valid text message.";
    } else if (isEmptyOrInvalid(rawText)) {
      validationError = `Text message is empty or contains only invalid characters: "${rawText}"`;
      userFriendlyError = "Your message appears to be empty or contains only special characters. Please send a valid text message.";
    } else {
      const sanitized = sanitizeMessage(rawText);
      if (sanitized.length === 0) {
        validationError = `Text message contains no valid content after sanitization. Original: "${rawText}"`;
        userFriendlyError = "Your message doesn't contain any valid text. Please try sending your message again.";
      } else if (isMeaningless(sanitized)) {
        validationError = `Message is too short or meaningless: "${sanitized}"`;
        userFriendlyError = "Your message is too short. Please send a complete message (at least 2-3 characters).";
      } else if (containsSuspiciousPatterns(sanitized)) {
        validationError = `Text message contains potentially malicious content: "${sanitized}"`;
        userFriendlyError = "Your message contains invalid content. Please send a normal text message.";
      } else if (isSpamPattern(sanitized)) {
        validationError = `Text message appears to be spam: "${sanitized}"`;
        userFriendlyError = "Your message looks unusual. Please send a normal message.";
      } else if (sanitized.length > 4096) {
        validationError = `Text message exceeds maximum length: ${sanitized.length} characters`;
        userFriendlyError = "Your message is too long. Please keep it under 4000 characters.";
      } else {
        isValid = true;
        messageContent = sanitized;
        messageType = 'text';
      }
    }
  } else if (message.type === 'interactive') {
    const interactive = message.interactive;
    if (!interactive) {
      validationError = "Interactive message data is missing";
      userFriendlyError = "Button/list selection failed. Please try clicking again.";
    } else if (interactive.type === 'button_reply' && interactive.button_reply) {
      const buttonId = interactive.button_reply.id;
      const buttonTitle = interactive.button_reply.title;
      if (!buttonId || isEmptyOrInvalid(buttonId)) {
        validationError = `Button reply ID is empty or invalid: "${buttonId}"`;
        userFriendlyError = "Button selection failed. Please try clicking the button again.";
      } else if (containsSuspiciousPatterns(buttonId)) {
        validationError = `Button reply contains malicious content: "${buttonId}"`;
        userFriendlyError = "Invalid button selection. Please contact support.";
      } else {
        const sanitizedId = sanitizeMessage(buttonId);
        if (sanitizedId.length === 0) {
          validationError = `Button ID empty after sanitization: "${buttonId}"`;
          userFriendlyError = "Button selection failed. Please try again.";
        } else {
          isValid = true;
          messageContent = sanitizedId;
          messageType = 'button_reply';
          item.json.buttonTitle = buttonTitle ? sanitizeMessage(buttonTitle) : null;
        }
      }
    } else if (interactive.type === 'list_reply' && interactive.list_reply) {
      const listId = interactive.list_reply.id;
      const listTitle = interactive.list_reply.title;
      const listDescription = interactive.list_reply.description;
      if (!listId || isEmptyOrInvalid(listId)) {
        validationError = `List reply ID is empty or invalid: "${listId}"`;
        userFriendlyError = "List selection failed. Please try selecting from the list again.";
      } else {
        const sanitizedId = sanitizeMessage(listId);
        if (sanitizedId.length === 0) {
          validationError = `List ID empty after sanitization: "${listId}"`;
          userFriendlyError = "List selection failed. Please try again.";
        } else {
          isValid = true;
          messageContent = sanitizedId;
          messageType = 'list_reply';
          item.json.listTitle = listTitle ? sanitizeMessage(listTitle) : null;
          item.json.listDescription = listDescription ? sanitizeMessage(listDescription) : null;
        }
      }
    } else {
      validationError = `Unsupported interactive type: '${interactive.type || 'unknown'}'`;
      userFriendlyError = "Unsupported selection type. Please use the provided buttons or lists.";
    }
  } else if (message.type === 'image') {
    validationError = "Image message received";
    userFriendlyError = "📸 Image messages are not supported here. Please send a text message instead.";
  } else if (message.type === 'video') {
    validationError = "Video message received";
    userFriendlyError = "🎥 Video messages are not supported. Please send a text message instead.";
  } else if (message.type === 'audio' || message.type === 'voice') {
    validationError = "Audio/voice message received";
    userFriendlyError = "🎤 Voice messages are not supported. Please send a text message instead.";
  } else if (message.type === 'document') {
    validationError = "Document message received";
    userFriendlyError = "📄 Document messages are not supported. Please send a text message instead.";
  } else if (message.type === 'sticker') {
    validationError = "Sticker message received";
    userFriendlyError = "😊 Stickers are not supported. Please send a text message instead.";
  } else {
    validationError = `Unknown message type: '${message.type}'`;
    userFriendlyError = "❌ This message type is not supported. Please send a text message.";
  }

  item.json.validation = {
    isValid: isValid,
    error: validationError,
    userFriendlyError: userFriendlyError,
    messageType: messageType,
    timestamp: new Date().toISOString()
  };

  if (isValid) {
    item.json.messageText = messageContent;
    item.json.messageType = messageType;
    item.json.senderId = item.json.contacts?.[0]?.wa_id || null;
    item.json.userName = item.json.contacts?.[0]?.profile?.name
      ? sanitizeMessage(item.json.contacts[0].profile.name)
      : "User";
    item.json.messageId = message.id || null;
    item.json.timestamp = message.timestamp || null;
    item.json.messageMetadata = {
      originalLength: messageType === 'text' ? (message.text?.body?.length || 0) : messageContent.length,
      sanitizedLength: messageContent.length,
      wordCount: messageContent.split(/\s+/).length,
      containsEmojis: /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]/u.test(messageContent),
      containsNumbers: /\d/.test(messageContent),
      containsUrls: /(https?:\/\/[^\s]+)/gi.test(messageContent),
      isQuestion: /[?？]/.test(messageContent),
      language: /[\u0900-\u097F]/.test(messageContent) ? 'hindi' :
                /[a-zA-Z]/.test(messageContent) ? 'english' : 'unknown'
    };
  } else {
    item.json.senderId = item.json.contacts?.[0]?.wa_id || null;
    item.json.userName = item.json.contacts?.[0]?.profile?.name || "User";
    item.json.messageId = message?.id || null;
  }
}

return items;

