const message = $input.first().json.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
const contact = $input.first().json.entry?.[0]?.changes?.[0]?.value?.contacts?.[0];

const buttonId = $input.first().json.messages[0].interactive.button_reply.id;
const waId = $input.first().json.contacts[0].wa_id;
const userName = $input.first().json.contacts[0].profile.name;

let prefix = null;
let productId = null;

if (buttonId?.startsWith("VTO_")) {
    prefix = "VTO_";
    productId = buttonId.substring(4);
} else if (buttonId?.startsWith("ORDER_")) {
    prefix = "ORDER_";
    productId = buttonId.substring(6);
}

$input.first().json.prefix = prefix;
$input.first().json.productId = productId;
$input.first().json.waId = waId;
$input.first().json.userName = userName;

return $input.first();

const productsJson = $input.first().json.cachedProductsJson;
const products = JSON.parse(productsJson);
console.log(`✅ Cache HIT - Found ${products.length} products.`);
return products.map(p => ({ json: p }));

const item = $input.first().json;
const userMessage = item.intentData.details;

// Generate a cache key based on the specific search details
const cacheKey = `cache:product:${userMessage.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 100)}`;

item.cacheKey = cacheKey;
return item;

const context = $('Get VTO context from Redis').first().json.propertyName;

return {
  json: {
    imageId: $('Route interactive vs image message').first().json.messages[0].image.id,
    waId: $('Route interactive vs image message').first().json.contacts[0].wa_id,
    productId: context
  }
}

const items = $input.all();

const productItems = items.filter(item => item.json.document && item.json.document.metadata);
const imageData = items.find(item => item.json.data && Array.isArray(item.json.data));

const products = productItems.map(item => item.json.document.metadata);

if (products.length === 0) {
  return [];
}

const base64Images = imageData && imageData.json.data ? imageData.json.data : [];

const productsWithImages = products.map((product, index) => {
  return {
    ...product,
    imageBase64: base64Images[index] || null
  };
});

const cacheKey = $('Build Redis cache key from search query').first().json.cacheKey;

return {
  json: {
    products: productsWithImages,
    productsJson: JSON.stringify(productsWithImages),
    cacheKey: cacheKey,
    totalProducts: productsWithImages.length,
    imagesAttached: base64Images.length
  }
};

// Get the item from the previous node
const item = $input.first().json;

// --- 1. Extract Data ---
const { senderId, messageText, sessionValue, userName } = item;

/**
 * Creates a new session object with default values.
 */
const createNewSession = (userId, uName) => {
  const currentTime = new Date().toISOString();
  return {
    userId: userId,
    userName: uName,
    messageHistory: [],
    createdAt: currentTime,
    lastActivity: currentTime,
    messageCount: 0
  };
};

// --- 2. Load or Create Session ---
let session;
let isNewSession = false;

if (sessionValue) {
  try {
    session = JSON.parse(sessionValue);
  } catch (e) {
    session = createNewSession(senderId, userName);
    isNewSession = true;
  }
} else {
  session = createNewSession(senderId, userName);
  isNewSession = true;
}

// --- 3. Update Session State ---
session.lastActivity = new Date().toISOString();
session.userName = userName;
session.messageCount = (session.messageCount || 0) + 1;

// Add user's message to history
session.messageHistory.push({
  role: 'user',
  content: messageText,
  timestamp: session.lastActivity
});

// Keep only the last 20 messages.
if (session.messageHistory.length > 20) {
  session.messageHistory = session.messageHistory.slice(-20);
}

// --- 4. Prepare Output ---
item.session = session;
item.isNewSession = isNewSession;

return item;

// This node adds the AI's final response to the session history.
const item = $input.first().json;

let session = item.session;

if (!session) {
  const currentTime = new Date().toISOString();
  session = {
    userId: item.senderId || item.contacts?.[0]?.wa_id || 'unknown_user',
    userName: item.userName || 'User',
    messageHistory: [],
    createdAt: currentTime,
    lastActivity: currentTime,
    messageCount: 0
  };
  item.session = session;
}

let assistantMessage = '';

if (item.responseType === 'json') {
  const intent = item.intentData.intent;
  const details = item.intentData.details;
  assistantMessage = `Understood intent: '${intent}'. Details: '${details}'.`;
  if (intent === 'product_search') {
      assistantMessage = `Okay, searching for: ${details}. Let me find some great options for you! 🛍️`;
  }
} else {
  assistantMessage = item.responseText;
}

session.messageHistory.push({
  role: 'assistant',
  content: assistantMessage,
  timestamp: new Date().toISOString()
});

if (session.messageHistory.length > 20) {
  session.messageHistory = session.messageHistory.slice(-20);
}

let userIdentifier = item.senderId;

if (!userIdentifier) {
  userIdentifier = item.contacts?.[0]?.wa_id;
}

if (!userIdentifier) {
  userIdentifier = session.userId;
}

item.redisKey = userIdentifier || `error_unknown_sender_${new Date().getTime()}`;
item.updatedSessionString = JSON.stringify(session);

return item;

// This node checks the AI's response, parses it if it's JSON, and sets a response type.
const item = $input.first().json;
const aiOutput = item.output;

// Default to a text response
item.responseType = 'text';
item.responseText = aiOutput;

if (typeof aiOutput === 'string' && aiOutput.trim().startsWith('{')) {
  try {
    const parsedJson = JSON.parse(aiOutput);
    if (typeof parsedJson === 'object' && parsedJson !== null && parsedJson.intent) {
      item.responseType = 'json';
      item.intentData = parsedJson;
      delete item.responseText;
    } else {
        item.responseText = "I received a response, but it was not in the expected format. Please try again.";
    }
  } catch (e) {
    console.log('Could not parse AI output as JSON. Treating as text.');
  }
} else if (typeof aiOutput !== 'string') {
    item.responseText = String(aiOutput);
}

return item;

const product = $input.first().json;
const to_number = $('WhatsApp message trigger').first().json.contacts[0].wa_id;

let senderId;
try {
  senderId = $('Load session and append user message').first().json.senderId;
} catch (error) {
  senderId = product.senderId || product.recipient_phone || to_number || '919638137734';
}

const productName = product.title || product.name || product.product_name || 'Product';
const price = product.price || product.product_price || '0';
const seller = product.seller_name || product.seller || 'In-House';
const availability = product.availability || product.stock_status || 'In Stock';
const productId = product._id || product.product_id || product.id || Date.now();

const formattedPrice = $input.first().json.discounted_price;

let bodyText = `🛍️ *${productName}*\n\n💰 *Price:* ₹${formattedPrice}\n🧑‍💼 *Seller:* ${seller}\n📦 *Availability:* ${availability}`;

const escapedBodyText = JSON.stringify(bodyText);

let imageBase64 = product.imageBase64 || product.image_base64 || product.base64Image || null;

if (imageBase64 && imageBase64.includes('base64,')) {
  imageBase64 = imageBase64.split('base64,')[1];
}

const returnData = {
  recipientPhone: senderId,
  to_number: to_number,
  bodyText: bodyText,
  bodyTextEscaped: escapedBodyText,
  productId: productId,
  productName: productName,
  price: formattedPrice,
  seller: seller,
  availability: availability,
  hasImage: !!imageBase64,
  originalProduct: product
};

if (imageBase64) {
  returnData.imageBase64 = imageBase64;
  returnData.imageType = 'image/jpeg';
  returnData.imageName = `${productName.replace(/[^a-zA-Z0-9]/g, '_')}.jpg`;
} else {
  returnData.imageBase64 = null;
  returnData.note = 'No image available for this product';
}

return {json: returnData};

const inputData = $input.first().json;
const imageBase64 = inputData.imageBase64;

if (!imageBase64) {
  return {
    json: {
      ...inputData,
      skipImageUpload: true
    }
  };
}

let cleanBase64 = imageBase64;
if (imageBase64.includes('base64,')) {
  cleanBase64 = imageBase64.split('base64,')[1];
}

return {
  json: inputData,
  binary: {
    data: {
      data: cleanBase64,
      mimeType: 'image/jpeg',
      fileName: inputData.imageName || 'product.jpg'
    }
  }
};

const items = $input.all();

let productImageBase64, userImageBase64, productImageUrl, userImageUrl;

if (items.length > 0) {
  const item = items[0].json;
  productImageBase64 = item.product_image_base64 || item.product_image || item.productImage;
  userImageBase64 = item.user_image_base64 || item.user_image || item.modelImage || item.userImage;
  productImageUrl = item.product_image_url || item.productImageUrl;
  userImageUrl = item.user_image_url || item.userImageUrl || item.modelImageUrl;
}

if (!productImageBase64 && !productImageUrl) {
  throw new Error('❌ Missing product/garment image data');
}
if (!userImageBase64 && !userImageUrl) {
  throw new Error('❌ Missing model/person image data');
}

const cleanProductImage = productImageBase64
  ? String(productImageBase64).replace(/^data:image\/[^;]+;base64,/, '').trim()
  : null;

const cleanUserImage = userImageBase64
  ? String(userImageBase64).replace(/^data:image\/[^;]+;base64,/, '').trim()
  : null;

const detectMimeType = (base64String) => {
  if (!base64String) return 'image/jpeg';
  const match = String(base64String).match(/^data:image\/([^;]+);base64,/);
  if (match) return `image/${match[1]}`;
  const signatures = {'/9j/': 'image/jpeg','iVBORw0KGgo': 'image/png','R0lGOD': 'image/gif','UklGR': 'image/webp'};
  for (const [sig, mime] of Object.entries(signatures)) {
    if (base64String.startsWith(sig)) return mime;
  }
  return 'image/jpeg';
};

const productMimeType = detectMimeType(productImageBase64);
const userMimeType = detectMimeType(userImageBase64);

const ultraAggressivePrompt = `Professional virtual try-on: Apply the garment from IMAGE 1 onto the person in IMAGE 2. Replace the existing upper body clothing with the new garment naturally and realistically. Keep the face, pose, background, and lower body unchanged.`;

const imageParts = [];

if (cleanProductImage) {
  imageParts.push({inlineData: {mimeType: productMimeType, data: cleanProductImage}});
} else if (productImageUrl) {
  imageParts.push({fileData: {mimeType: "image/jpeg", fileUri: productImageUrl}});
}

if (cleanUserImage) {
  imageParts.push({inlineData: {mimeType: userMimeType, data: cleanUserImage}});
} else if (userImageUrl) {
  imageParts.push({fileData: {mimeType: "image/jpeg", fileUri: userImageUrl}});
}

const apiPayload = {
  contents: [{role: "user", parts: [{text: ultraAggressivePrompt}, ...imageParts]}],
  generationConfig: {temperature: 0.2, topP: 0.9, topK: 30, maxOutputTokens: 8192, candidateCount: 1},
  safetySettings: [
    {category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_ONLY_HIGH"},
    {category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_ONLY_HIGH"},
    {category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_MEDIUM_AND_ABOVE"},
    {category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_ONLY_HIGH"}
  ]
};

return [{json: {product_image_clean: cleanProductImage, user_image_clean: cleanUserImage, product_mime_type: productMimeType, user_mime_type: userMimeType, api_payload: apiPayload, timestamp: new Date().toISOString()}}];
